import WorkerClient from '../worker/client'
import Placement from './placement'
import Shots from '../models/shots'
import PayloadNormalize from './payload_normalize'
import SceneProcessor from './processors/scene'
import ShotsProcessor from './processors/shots'

import { FpsMeter, wait } from '../tools'
import { shuffle } from 'lodash-es'

const DESIRED_FRAME_RATE = 53; // 62;
const DESIRED_FRAME_TIME = 1000 / DESIRED_FRAME_RATE;

export default class Engine {
  constructor(teams, arena, renderer, options = {}) {
    this.teams = teams;
    this.arena = arena;
    this.shots = new Shots();
    this.renderer = renderer;
    this.client = new WorkerClient();
    this.positionMode = options.positionMode || "random";
    this.bulletMode = options.bulletMode || "vertical";
    this.payloadNormalize = new PayloadNormalize(this.arena);

    this.dataArguments = {
      arena: this.arena,
      teams: this.teams,
      shots: this.shots
    };

    this.sceneProcessor = new SceneProcessor(this.dataArguments);
    this.shotsProcessor = new ShotsProcessor(this.dataArguments);

    this.fpsMeter = new FpsMeter();
  }

  resetMeasureCounters() {
    this.measureRender = 0;
    this.measureWorkers = 0;
    this.measureParallelInvoke = 0;
    this.measureAll = 0;
    this.statistics = [];
  }

  stop() {
    this.stopFlag = true;
    setTimeout(() => this.detachWorkers && this.detachWorkers(), 500);
  }

  async run() {
    this.reactiveBots();
    this.applyPlacement();
    this.renderer.setup(this.dataArguments);
    await this.client.registerBots(this.teams.allBots());

    this.fpsMeter.reset();
    this.resetMeasureCounters();
    let count = 0;

    while (!this.stopFlag) {
      count++;
      this.currentStats = {};
      this.currentStats.botsCount = this.teams.activeBots().length;
      this.currentStats.allShotsCount = this.shots.length;
      this.currentStats.explodedShotsCount = [...this.shots.shots].filter(s => s.exploded).length;
      const startTime = performance.now();

      const promiseBotsPayload = this.safeExecuteBots();
      this.render();
      const payload = await promiseBotsPayload;

      this.measureParallelInvoke += (this.currentStats.parallelInvokeTime = performance.now() - startTime);

      if (payload) {
        this.sceneProcessor.execute(payload);
        this.shotsProcessor.execute(this.bulletMode);
      }

      const frameTime = performance.now() - startTime;
      this.currentStats.frameTime = frameTime;
      this.currentStats.waitTime = DESIRED_FRAME_TIME - frameTime;
      if (DESIRED_FRAME_TIME - frameTime > 5)
      await wait(DESIRED_FRAME_TIME - frameTime);


      const totalFrameTime = performance.now() - startTime;
      this.currentStats.actualWaitTime = totalFrameTime - frameTime;
      this.currentStats.totalFrameTime = totalFrameTime;
      this.statistics.push(this.currentStats);
      this.measureAll += totalFrameTime;
      this.fpsMeter.track(1000 / totalFrameTime);
      this.renderer.writeFPS(this.fpsMeter.averageInt());
    }

    this.detachWorkers = null;
    this.clearBotErrors();

    console.log(`Workers time: ${this.measureWorkers}`);
    console.log(`Render time: ${this.measureRender}`);
    console.log(`All time: ${this.measureParallelInvoke}`);
    console.log(`FPS: ${count * 1000 / this.measureAll}`);
  }

  render() {
    const startTimeRender = performance.now();
    this.renderer.render();
    this.measureRender += (this.currentStats.renderTime = performance.now() - startTimeRender);
  }

  safeExecuteBots() {
    return new Promise(resolve => {
      this.detachWorkers = resolve;
      this.executeBots().then(resolve);
    });
  }

  async executeBots() {
    const startTime = performance.now();
    const result = await this.client.executeBots(
      shuffle(this.teams.toJson()),
      this.shots.toJson(),
      this.arena.toJson()
    );

    Object.keys(result).forEach(botId => {
      const { payload, error } = result[botId];

      if (!error) {
        result[botId] = this.payloadNormalize.execute(payload);
      } else {
        delete result[botId];
      }
    })

    this.measureWorkers += performance.now() - startTime;
    return result;
  }

  reactiveBots() {
    this.teams.allBots().map(bot => bot.reactivate());
  }

  applyPlacement() {
    const placement = new Placement(this.positionMode, this.arena);
    placement.applyTo(this.teams.allBots());
  }

  clearBotErrors() {
    this.teams.activeBots().forEach(bot => bot.errored = false);
    this.renderer.render();
  }

  destroy() {
    this.client.destroy();
    this.shots.destroy();
  }
}
