export function distance(x1, y1, x2, y2) {
  return Math.sqrt(Math.pow(x1 - x2, 2) + Math.pow(y1 - y2, 2));
}

export function distanceBetweenObjects(object1, object2) {
  return distance(object1.x, object1.y, object2.x, object2.y);
}

export function clearAngle(angle) {
  const result = angle % 360;
  return result < 0 ? result + 360 : result;
}

export function direction(fromX, fromY, toX, toY) {
  if (fromX === toX)
    return fromY < toY ? 270 : 90;
  if (fromY === toY)
    return fromX < toX ? 0 : 180;

  return clearAngle(-Math.atan2(toY - fromY, toX - fromX) * 180 / Math.PI);
}

export function directionBetweenObjects(object1, object2) {
  return direction(object1.x, object1.y, object2.x, object2.y);
}

export function normalize360(angle) {
  return clearAngle(angle);
}

export function normalize180(angle) {
  let a = angle % 360;
  if (Math.abs(a) > 180)
    a += a < 0 ? 360 : -360;
  return a;
}

export function angleSize(from, to) {
  return normalize180(to - from);
}

export function getIntersectionOfTwoLines(x11, y11, x12, y12, x21, y21, x22, y22) {
  if (x12 - x11 !== 0) {
    const k1 = (y12 - y11) / (x12 - x11);
    const b1 = y11 + (-x11 * (y12 - y11) / (x12 - x11));
    const k2 = (y22 - y21) / (x22 - x21);
    const b2 = y21 + (-x21 * (y22 - y21) / (x22 - x21));
    let x, y;

    if (k1 - k2 !== 0) {
      x = (b2 - b1) / (k1 - k2);
      y = (k1 * x) + b1;
      return [x, y];
    } else {
      return null;
    }

  } else {
    if (x22 - x21 === 0) return null;

    const k2 = (y22 - y21) / (x22 - x21);
    const b2 = y21 + (-x21 * (y22 - y21) / (x22 - x21));
    return [x11, k2 * x11 + b2];
  }
}
