import React from 'react'
import ReactDOM from 'react-dom'
import { Provider } from 'react-redux'
import { createStore, applyMiddleware, compose } from 'redux'
import ReduxLogger from 'redux-logger'
import ReduxThunk from 'redux-thunk'
import reducer from './reducers'
import { loadFromLocalStorage, syncWithLocalStorage } from 'helpers/syncStore'

import './index.css'
import App from './components/App'
import reportWebVitals from './reportWebVitals'

// eslint-disable-next-line import/no-webpack-loader-syntax
import workerScriptUrl from 'worker-plugin/loader?name=worker&esModule!./worker'

// Register worker url
const meta = document.createElement('meta');
meta.name = 'worker.js';
meta.content = workerScriptUrl;
document.head.appendChild(meta);

// Create redux store
const composeEnhancers = window.__REDUX_DEVTOOLS_EXTENSION_COMPOSE__ || compose;
const store = createStore(reducer, loadFromLocalStorage(), composeEnhancers(
  applyMiddleware(ReduxThunk, ReduxLogger)
));

syncWithLocalStorage(store);

// Render application
ReactDOM.render(
  <React.StrictMode>
    <Provider store={store}>
      <App />
    </Provider>
  </React.StrictMode>,
  document.getElementById('botality-root')
);

// If you want to start measuring performance in your app, pass a function
// to log results (for example: reportWebVitals(console.log))
// or send to an analytics endpoint. Learn more: https://bit.ly/CRA-vitals
reportWebVitals();
