import WorkerWrapper from './wrapper'

const DEFAULT_CONCURRENCY = 2;
const WORKER_PREFIX = 'bot_w_';
const WORKER_META_TAG = 'worker.js';

let sequence = 0;

export default class Pool {
  static get concurrency() {
    const navigator = window.navigator;
    return (navigator && navigator.hardwareConcurrency) || DEFAULT_CONCURRENCY;
  }

  static get workerUrl() {
    const meta = document.querySelector(`head > meta[name='${WORKER_META_TAG}']`);
    return meta && meta.content;
  }

  constructor(count = this.constructor.concurrency) {
    this.count = count;
    this.workers = {};
    this.initiatePool();
  }

  initiatePool() {
    for (let i = 0; i < this.count; i++) {
      sequence++;
      const name = WORKER_PREFIX + sequence;
      this.workers[name] = new WorkerWrapper(this.constructor.workerUrl, { name });
    }
  }

  stats() {
    return Object.keys(this.workers).map(name => ({
      name,
      load: this.workers[name].tracker.load()
    }));
  }

  destroy() {
    Object.values(this.workers).forEach(w => w.terminate());
    this.workers = {};
  }
}
