import { useRef, useState, useEffect } from 'react'
import { sortBy } from 'lodash-es'

const elements = {}

const triggerStayOnTopChanges = () => {
  Object.values(elements).forEach(([set, idx]) => set(idx))
}

const normalizeStayOnTopIndexes = () => {
  sortBy(Object.values(elements), ([_, idx]) => idx)
    .forEach((el, idx) => el[1] = idx + 1)
}

const nextStayOnTopIndex = () => {
  const indexes = Object.values(elements).map(e => e[1])
  return Math.max(0, ...indexes) + 1
}

export default function useStayOnTop() {
  const elementId = useRef(Math.max(0, ...Object.keys(elements)) + 1)
  const [stayOnTopIndex, setStayOnTopIndex] = useState(null)

  const activate = () => {
    elements[elementId.current][1] = nextStayOnTopIndex()
    normalizeStayOnTopIndexes()
    triggerStayOnTopChanges()
  }

  const prepareActivation = () => {
    const id = elementId.current

    if (stayOnTopIndex) {
      const exists = Object.values(elements).find(([_, idx]) => idx === stayOnTopIndex)

      if (exists) {
        Object.values(elements)
          .filter(([_, idx]) => idx >= stayOnTopIndex)
          .forEach(el => el[1]++)
      }

      elements[id] = [setStayOnTopIndex, stayOnTopIndex]
      exists && triggerStayOnTopChanges()
    } else {
      const newIndex = nextStayOnTopIndex()
      elements[id] = [setStayOnTopIndex, newIndex]
      setStayOnTopIndex(newIndex)
    }

    return () => delete elements[id]
  }

  useEffect(prepareActivation)

  return [stayOnTopIndex, activate]
}
