import { isArray, isNaN, isBoolean } from 'lodash-es'
import { distance } from './math_helper'

export default class PayloadNormalize {
  constructor(arena) {
    this.maxRange = distance(0, 0, arena.width, arena.height) + 100;
  }

  execute(payload) {
    if (!isArray(payload)) {
      payload = [];
    }

    payload[0] = this.normalizeNumber(payload[0], 0, 1);
    payload[1] = this.normalizeNumber(payload[1], -1, 1);
    payload[2] = this.normalizeBoolean(payload[2]);
    payload[3] = this.normalizeNumber(payload[3], 0, this.maxRange);
    return payload;
  }

  normalizeNumber(value, min, max) {
    let parsed = parseFloat(value, 10);
    if (isNaN(parsed)) { parsed = 0; }
    return Math.max(Math.min(parsed, max), min);
  }

  normalizeBoolean(value) {
    return isBoolean(value) ? value : false;
  }
}
