import React from 'react'
import PropTypes from 'prop-types'
import Gauge from 'components/shared/Gauge'
import { useSelector } from 'react-redux'
import { useSimulationContext } from 'helpers/simulationCache'

const colorFunction = value => {
  if (value < 75) {
    return '#5ee432';
  } else if (value < 90) {
    return '#f7aa38';
  } else {
    return '#ef4655';
  }
}

const STATS_PLACEHOLDER = Array(4).fill().map((_, index) => ({
  name: index + 1,
  load: 0
}))

const WorkerStats = ({ simulationId: id }) => {
  const { workers: stats = STATS_PLACEHOLDER } = useSimulationContext(id)
  const { running } = useSelector(store => store.simulations[id])

  return <>
    <h4 style={{ marginBottom: 0, textAlign: 'center' }}>
      Workers
    </h4>
    <div style={{ display: 'flex', flexDirection: 'row', flexWrap: 'wrap', maxWidth: 200 }}>
      {
        stats.map((worker, index) => (
          <div key={worker.name}>
            <Gauge
              value={running ? worker.load * 100 : 0}
              color={colorFunction}
              label={() => `#${index + 1}`} />
          </div>
        ))
      }
    </div>
  </>
}

WorkerStats.displayName = 'WorkerStats'
WorkerStats.propTypes = {
  simulationId: PropTypes.string.isRequired
}

export default WorkerStats
