export default class Arena {
  constructor(params = {}) {
    this.update(params);
  }

  update(params = {}) {
    this.width = params.width || 800;
    this.height = params.height || 700;
    this.botRadius = params.botRadius || 15;
    this.shotSpeed = params.shotSpeed || 12;
  }

  toJson() {
    return {
      arena_width: this.width,
      arena_height: this.height,
      robot_radius: this.botRadius,
      shot_speed: this.shotSpeed
    };
  }
}
