import Tracker from './tracker'

export default class Wrapper {
  constructor(url, options) {
    this.resolves = {};
    this.rejects = {};
    this.sequenceMessageId = 0;
    this.name = options.name;
    this.tracker = new Tracker();

    // create and hook up web worker
    this.worker = new Worker(url, options);
    this.onmessage = this.onMessageResponse.bind(this);
  }

  set onmessage(handler) {
    this.worker.onmessage = handler;
  }

  onMessageResponse(event) {
    this.tracker.stopJob();

    const { id: messageId, payload, error } = event.data;
    const resolve = this.resolves[messageId];
    const reject = this.rejects[messageId];

    if (error && reject) {
      reject({ error, payload });
    } else if (resolve) {
      resolve(payload);
    } else {
      throw new Error(`[WorkerWrapper "${this.name}"] Promises callback wasn't found for message ID: ${messageId}`);
    }

    delete this.resolves[messageId];
    delete this.rejects[messageId];
  }

  postMessage(payload) {
    const messageId = this.sequenceMessageId++;
    const message = {
      id: messageId,
      payload: payload
    }

    return new Promise((resolve, reject) => {
      this.resolves[messageId] = resolve;
      this.rejects[messageId] = reject;

      this.tracker.startJob();
      this.worker.postMessage(message);
    });
  }

  terminate() {
    return this.worker.terminate();
  }
}
