import React from 'react'
import PropTypes from 'prop-types'
import { useSelector, useDispatch } from 'react-redux'
import { FaPlay, FaStop } from 'react-icons/fa'
import Button from 'components/shared/Button'
import Teams from './Teams'
import WorkerStats from './WorkerStats'
import { updateSettings } from 'actions'

const BULLET_MODE_OPTIONS = ['vertical', 'horizontal']
const POSITION_MODE_OPTIONS = ['random', 'opposite']

const ControlPanel = ({ simulationId, startSimulation, stopSimulation }) => {
  const dispatch = useDispatch()
  const { running, settings } = useSelector(store => store.simulations[simulationId])

  const onChange = field => event => {
    dispatch(updateSettings(simulationId, {
      [field]: event.target.value
    }))
  }

  return (
    <div style={{ display: 'flex', flexDirection: 'row', padding: 15 }}>
      <div style={{ display: 'flex', flexDirection: 'column' }}>
        <div style={{ display: 'flex', flexDirection: 'row' }}>
          <Button
            onClick={running ? stopSimulation : startSimulation}
            style={{ width: 80, height: 80 }}
          >
            {running ? <FaStop size="3em" /> : <FaPlay size="3em" />}
          </Button>

          <div style={{ display: 'flex', flexDirection: 'column', padding: 5 }}>
            <div>
              <label htmlFor="bulletMode">Bullet mode:</label>
              <br />
              <select
                name="bulletMode"
                onChange={onChange('bulletMode')}
                value={settings.bulletMode}
                disabled={running}
              >
                {
                  BULLET_MODE_OPTIONS.map(name => (
                    <option key={name} value={name}>{name}</option>
                  ))
                }
              </select>
            </div>

            <div>
              <label htmlFor="positionMode">Position:</label>
              <br />
              <select
                name="positionMode"
                onChange={onChange('positionMode')}
                value={settings.positionMode}
                disabled={running}
              >
                {
                  POSITION_MODE_OPTIONS.map(name => (
                    <option key={name} value={name}>{name}</option>
                  ))
                }
              </select>
            </div>
          </div>
        </div>

        <WorkerStats simulationId={simulationId} />
      </div>

      <Teams simulationId={simulationId} />
    </div>
  )
}

ControlPanel.displayName = 'ControlPanel'
ControlPanel.propTypes = {
  simulationId: PropTypes.string.isRequired,
  startSimulation: PropTypes.func.isRequired,
  stopSimulation: PropTypes.func.isRequired
}

export default ControlPanel
