import React, { useEffect, useState, useRef, useCallback } from 'react'
import PropTypes from 'prop-types'
import useStayOnTop from './hooks/useStayOnTop'
import classes from './Modal.module.scss'

const body = document.body || document.getElementsByTagName('body')[0]

const normalizeX = x => {
  return Math.min(
    Math.max(x, 0),
    Math.max(body.offsetWidth - 40, 0)
  )
}

const normalizeY = y => {
  return Math.min(
    Math.max(y, 0),
    Math.max(body.offsetHeight - 40, 0)
  )
}

const ResizeAndDrag = ({ style = {}, children }) => {
  const rootRef = useRef(null)
  const stateRef = useRef()

  const [dragging, setDragging] = useState(false)
  const [resizing, setResizing] = useState(false)
  const [rect, setRect] = useState(null)
  const [triggerState, setTriggerState] = useState({
    x: 0,
    y: 0,
    modal: {},
    target: null
  })

  stateRef.current = {
    rect,
    dragging,
    resizing,
    triggerState
  }

  const [stayOnTopIndex, activate] = useStayOnTop()

  useEffect(() => {
    if (rootRef.current && !rect) {
      setTimeout(() => {
        const rootRect = rootRef.current.getBoundingClientRect()

        setRect({
          top: rootRect.top,
          left: rootRect.left,
          width: rootRect.width,
          height: rootRect.height
        })
      })
    }
  }, [rect])

  const onMouseMove = useCallback(event => {
    const { dragging, resizing, triggerState, rect } = stateRef.current;

    if (dragging) {
      triggerState.target.style.cursor = 'grabbing'
      const moveX = event.pageX - triggerState.x
      const moveY = event.pageY - triggerState.y

      setRect({
        ...rect,
        top: normalizeY(triggerState.modal.top + moveY),
        left: normalizeX(triggerState.modal.left + moveX)
      })
    } else if (resizing) {
      const moveX = event.pageX - triggerState.x
      const moveY = event.pageY - triggerState.y

      setRect({
        ...rect,
        width: Math.max(triggerState.modal.width + moveX, 300),
        height: Math.max(triggerState.modal.height + moveY, 150)
      })
    }
  }, [stateRef])

  const onMouseUp = useCallback(() => {
    const { dragging, resizing, triggerState } = stateRef.current;

    if (dragging) {
      triggerState.target.style.removeProperty('cursor')
      setDragging(false)
    }

    if (resizing) {
      setResizing(false)
    }
  }, [stateRef])

  const initiateState = event => {
    setTriggerState({
      x: event.pageX,
      y: event.pageY,
      modal: { ...rect },
      target: event.target
    })
  }

  const onDragStart = event => {
    if (event.target.classList.contains('draggable')) {
      initiateState(event)
      setDragging(true)
    }
  }

  const onResizeStart = event => {
    initiateState(event)
    setResizing(true)
  }

  useEffect(() => {
    document.addEventListener('mouseup', onMouseUp)
    document.addEventListener('mousemove', onMouseMove)

    return () => {
      document.removeEventListener('mousemove', onMouseMove)
      document.removeEventListener('mouseup', onMouseUp)
    }
  }, [onMouseUp, onMouseMove])

  const extendedChildren = React.Children.map(children, child => {
    const classNames = (child.props.className || '').split(' ')
    const hasDraggable = classNames.includes('draggable')

    return !hasDraggable ? child : React.cloneElement(child, {
      style: { cursor: 'default', userSelect: 'none' },
      onMouseDown: event => {
        onDragStart(event);
        child.props.onMouseDown && child.props.onMouseDown(event);
      }
    })
  })

  const activeStyle = { zIndex: 770 + (stayOnTopIndex || 0) }

  return (
    <div
      className={classes.modal}
      ref={rootRef}
      style={{ ...style, ...rect, ...activeStyle }}
      onMouseDown={activate}>
      <div className={classes.resizeAnchor} onMouseDown={onResizeStart} />
      <div className={classes.container}>
        {extendedChildren}
      </div>
    </div>
  )
}

ResizeAndDrag.displayName = 'ResizeAndDrag'
ResizeAndDrag.propTypes = {
  style: PropTypes.object
}

export default ResizeAndDrag
