import React, { useState, useEffect } from 'react'
import { useSelector, useDispatch } from 'react-redux'
import PropTypes from 'prop-types'
import Scene from './Scene'
import ControlPanel from './ControlPanel'
import { addSimulation, setRunning } from 'actions'

import { lookupSimulationEngine } from 'helpers/simulationCache'
import { lookupSimulationContext } from 'helpers/simulationCache'

const Simulation = ({ id }) => {
  const [stats, setStats] = useState({})
  const dispatch = useDispatch()
  const state = useSelector(store => store.simulations[id])
  const settings = state ? state.settings : { settings: {} }
  const { width, height, positionMode, bulletMode } = settings

  const { Provider } = lookupSimulationContext(id)
  const sim = lookupSimulationEngine(id)
  sim.changeArena({ width, height })

  const onStatsChange = setStats
  const onRunningChange = running => {
    dispatch(setRunning(id, running))
  }

  useEffect(() => {
    const unsubscribes = [
      sim.on('runningchange', onRunningChange),
      sim.on('statistics', onStatsChange)
    ]

    return () => unsubscribes.forEach(unsub => unsub())
  })

  const startSimulation = () => {
    if (!sim.running) {
      sim.setupTeams(state.teams)
      sim.start({ positionMode, bulletMode })
    }
  }

  const stopSimulation = () => {
    sim.stop()
  }

  const rendererResize = ({ width, height }) => {
    sim.renderer.resize(width, height)
  }

  if (!state) {
    dispatch(addSimulation(id))

    return <div style={{
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      height: 'calc(100vh - 50px)'
    }}>
      Loading...
    </div>
  }

  return <div className="simulation">
    <Provider value={stats}>
      <ControlPanel
        simulationId={id}
        startSimulation={startSimulation}
        stopSimulation={stopSimulation} />
      <Scene
        simulationId={id}
        setRenderContext={sim.setRenderContext.bind(sim)}
        rendererResize={rendererResize} />
    </Provider>
  </div>
}

Simulation.displayName = 'Simulation'
Simulation.propTypes = {
  id: PropTypes.string.isRequired
}

export default Simulation
