import { some } from 'lodash-es'
import { normalize360, distance } from '../math_helper'

const GAIN_ENERGY = 0.3;
const NORMAL_SPEED_THRESHOLD = 0.5;
const EXTRA_SPEED_ENERGY_MULTIPLIER = 5;

export default class Scene {
  constructor({ arena, teams, shots }) {
    this.arena = arena;
    this.teams = teams;
    this.shots = shots;
  }

  execute(payload) {
    const bots = this.teams.activeBots();

    bots.forEach(bot => {
      bot.errored = !payload.hasOwnProperty(bot.id);
      if (bot.errored) return;

      const [step, rotate, shoot, shootRange] = payload[bot.id];

      if (shoot && bot.fullEnergy()) {
        this.shots.add({
          x: bot.x,
          y: bot.y,
          angle: bot.angle,
          range: shootRange,
          shooter: bot.id
        });

        bot.energy = 0.0;
      }

      let speed = step;
      if (speed > NORMAL_SPEED_THRESHOLD && !bot.hasEnergy(this.extraSpeedEnergyConsume(speed))) {
        speed = NORMAL_SPEED_THRESHOLD;
      }

      const angle = normalize360(bot.angle + rotate);
      const x = bot.x + speed * Math.cos(angle * Math.PI / 180);
      const y = bot.y - speed * Math.sin(angle * Math.PI / 180);

      bot.angle = angle;
      bot.addEnergy(GAIN_ENERGY);

      if (!this.anyCollisionsWith(x, y, bot, bots)) {
        bot.x = x;
        bot.y = y;
        bot.addEnergy(-this.extraSpeedEnergyConsume(speed));
      }
    });
  }

  anyCollisionsWith(newX, newY, bot, bots) {
    if (newX < this.arena.botRadius || newX > (this.arena.width - this.arena.botRadius) ||
        newY < this.arena.botRadius || newY > (this.arena.height - this.arena.botRadius)) {
      return true;
    }

    return some(bots, currentBot => {
      if (bot === currentBot) return false;
      const dist = distance(currentBot.x, currentBot.y, newX, newY);
      return dist < 2 * this.arena.botRadius;
    });
  }

  extraSpeedEnergyConsume(speed) {
    const extra = Math.max(0, speed - NORMAL_SPEED_THRESHOLD);
    return extra * EXTRA_SPEED_ENERGY_MULTIPLIER;
  }
}
