export default class Bot {
  static get MAX_HEALTH() { return 100; }
  static get MAX_ENERGY() { return 100; }

  constructor(data) {
    this.id = data.id;
    this.team = data.team;
    this.initiateGameData();
  }

  get color() {
    return this.team.color;
  }

  get name() {
    return this.team.name;
  }

  get script() {
    return this.team.script;
  }

  initiateGameData() {
    this.reactivate();
    this.x = 0;
    this.y = 0;
    this.angle = 0;
    this.errored = false;
  }

  reactivate() {
    this.active = true;
    this.health = this.constructor.MAX_HEALTH;
    this.energy = this.constructor.MAX_ENERGY;
  }

  fullEnergy() {
    return this.energy >= this.constructor.MAX_ENERGY;
  }

  hasEnergy(value) {
    return this.energy >= value;
  }

  addEnergy(value) {
    return this.energy = Math.max(0, Math.min(this.energy + value, this.constructor.MAX_ENERGY));
  }

  kill() {
    this.health = 0;
    this.energy = 0;
    this.active = false;
  }

  toJson() {
    return {
      id: this.id,
      team: this.name,
      x: this.x,
      y: this.y,
      health: this.health,
      energy: this.energy,
      angle: this.angle
    };
  }
}
