import Base from './base'
import './dom.scss'

const RENDERER_CLASS = 'dom-renderer-canvas';
const BOTS_CONTAINER_CLASS = 'bots';
const SHOTS_CONTAINER_CLASS = 'shots';
const EXPLOSIONS_CONTAINER_CLASS = 'explosions';

const EXPLOSION_CLASS = 'explosion';

const BOT_CLASS = 'bot';
const BOT_DIED_CLASS = 'died';
const BOT_ERRORED_CLASS = 'errored';
const BARREL_CLASS = 'barrel';
const HEALTH_METER_CLASS = 'health';
const ENERGY_METER_CLASS = 'energy';

const SHOT_CLASS = 'shot';
const HIDDEN_CLASS = 'hidden';
const ADD_SHOTS_DELTA = 10;

const FPS_LABEL_CLASS = 'fps-meter';

export default class Dom extends Base {
  constructor(element) {
    super(element);

    this.init();
    this.createAndRegisterContainers();
    this.element.classList.add(RENDERER_CLASS);
  }

  setup(data) {
    super.setup(data);

    this.cleanup();
    this.addFpsMeter();
    this.createBotsElements();
    this.createMissingShotsElements();
    this.setArenaOffset();
  }

  init() {
    this.botsDomMapper = {};
    this.shotsDomList = [];
  }

  cleanup() {
    this.emptyNode(this.botsContainer);
    this.emptyNode(this.shotsContainer);
    this.emptyNode(this.explosionsContainer);
    this.init();
  }

  render() {
    this.renderBots();
    this.createMissingShotsElements();
    this.renderShots();
  }

  resize(width, height) {
    this.applyStyles(this.element, {
      width,
      height
    })
  }

  writeFPS(value) {
    if (this.fpsMeter) {
      this.fpsMeter.textContent = value;
    }
  }

  renderBots() {
    this.teams.allBots().forEach(bot => {
      const node = this.botsDomMapper[bot.id];

      if (!bot.active) {
        node.classList.add(BOT_DIED_CLASS);
        return;
      }

      node.classList.toggle(BOT_ERRORED_CLASS, bot.errored);

      this.applyStyles(node, { left: bot.x, top: bot.y });

      this.applyStyles(node.querySelector(`.${BARREL_CLASS}`), {
        transform: `rotate(${180 - bot.angle}deg)`
      });

      this.applyStyles(node.querySelector(`.${HEALTH_METER_CLASS}`), {
        '--meter-width': bot.health / bot.constructor.MAX_HEALTH
      });

      this.applyStyles(node.querySelector(`.${ENERGY_METER_CLASS}`), {
        '--meter-width': bot.energy / bot.constructor.MAX_ENERGY
      });
    });
  }

  renderShots() {
    let index = 0;

    for (const shot of this.shots.shots) {
      const node = this.shotsDomList[index++];

      if (shot.exploded) {
        node.classList.add(HIDDEN_CLASS);
        shot.explosionStarted() && this.renderExploded(shot);
      } else {
        node.classList.remove(HIDDEN_CLASS);
        this.applyStyles(node, {
          left: shot.x,
          top: shot.y,
          '--rotate': `${180 - shot.angle}deg`
        });
      }
    }

    this.shotsDomList.slice(this.shots.length).forEach(node => {
      node.classList.add(HIDDEN_CLASS)
    });
  }

  renderExploded(shot) {
    const node = this.createNode(`
      <div class="${EXPLOSION_CLASS}">
        <div class="body"></div>
        <div class="track"></div>
      </div>
    `, {
      styles: {
        left: shot.x,
        top: shot.y
      }
    });

    this.explosionsContainer.appendChild(node);
  }

  addFpsMeter() {
    this.fpsMeter = this.element.querySelector(`.${FPS_LABEL_CLASS}`);

    if (!this.fpsMeter) {
      this.fpsMeter = this.createNode(`<div class="${FPS_LABEL_CLASS}">`);
      this.element.appendChild(this.fpsMeter);
    }
  }

  createAndRegisterContainers() {
    this.botsContainer = this.element.querySelector(`.${BOTS_CONTAINER_CLASS}`);

    if (!this.botsContainer) {
      this.botsContainer = this.createNode(`<div class="${BOTS_CONTAINER_CLASS}">`);
      this.element.appendChild(this.botsContainer);
    }

    this.shotsContainer = this.element.querySelector(`.${SHOTS_CONTAINER_CLASS}`);

    if (!this.shotsContainer) {
      this.shotsContainer = this.createNode(`<div class="${SHOTS_CONTAINER_CLASS}">`);
      this.element.appendChild(this.shotsContainer);
    }

    this.explosionsContainer = this.element.querySelector(`.${EXPLOSIONS_CONTAINER_CLASS}`);

    if (!this.explosionsContainer) {
      this.explosionsContainer = this.createNode(`<div class="${EXPLOSIONS_CONTAINER_CLASS}">`);
      this.element.appendChild(this.explosionsContainer);
    }
  }

  setArenaOffset() {
    this.applyStyles(this.botsContainer, {
      'margin-left': -this.arena.botRadius,
      'margin-top': -this.arena.botRadius
    });
  }

  createBotsElements() {
    this.teams.allBots().forEach(bot => {
      const botNode = this.createBotElement(bot);
      this.botsDomMapper[bot.id] = botNode;
      this.botsContainer.appendChild(botNode);
    });
  }

  createBotElement(bot) {
    const template = `
      <div class="${BOT_CLASS}" name="${bot.id}">
        <div class="body"></div>
        <div class="${BARREL_CLASS}"></div>
        <div class="${HEALTH_METER_CLASS}"></div>
        <div class="${ENERGY_METER_CLASS}"></div>
      </div>`;

    return this.createNode(template, {
      styles: {
        left: bot.x,
        top: bot.y,
        width: this.arena.botRadius * 2,
        height: this.arena.botRadius * 2,
        '--background-color': bot.color
      }
    });
  }

  createMissingShotsElements() {
    const desiredShotsNumber = Math.ceil(this.shots.length / ADD_SHOTS_DELTA) * ADD_SHOTS_DELTA;
    const newShotsNumber = Math.max(0, desiredShotsNumber - this.shotsDomList.length);
    if (newShotsNumber === 0) return;

    const newShots = Array.from(Array(newShotsNumber)).map(() => {
      return this.createNode(`<div class="${[SHOT_CLASS, HIDDEN_CLASS].join(' ')}">`);
    });

    newShots.forEach(s => this.shotsContainer.appendChild(s));
    this.shotsDomList.push(...newShots);
  }

  createNode(html, { attrs, styles } = {}) {
    const tempEl = document.createElement('div');
    tempEl.innerHTML = html;
    const el = tempEl.children[0];
    attrs && this.applyAttributes(el, attrs);
    styles && this.applyStyles(el, styles);
    return el;
  }

  emptyNode(node) {
    while (node.firstChild) {
      node.removeChild(node.lastChild);
    }
  }

  applyAttributes(node, attrs) {
    Object.keys(attrs).forEach(key => {
      node.setAttribute(key, attrs[key]);
    });
  }

  applyStyles(node, styles) {
    Object.keys(styles).forEach(key => {
      let value = styles[key];
      value = typeof value === 'number' && !key.startsWith('--')
        ? `${value}px`
        : value;
      node.style.setProperty(key, value);
    });
  }
}
