import produce from 'immer'
import * as Types from 'actions/types'

const INITIAL_STATE = {}

export default function simulationReducer(state = INITIAL_STATE, action) {
  switch (action.type) {
    case Types.ADD_SIMULATION:
      return {
        ...state,
        [action.id]: action.simulation
      }

    case Types.UPDATE_SETTINGS:
      const { settings } = state[action.id]

      return produce(state, draft => {
        draft[action.id].settings = {
          ...settings,
          ...action.changes
        }
      })

    case Types.SET_RUNNING:
      return produce(state, draft => {
        draft[action.id].running = !!action.running
      })

    case Types.ADD_TEAM:
      return produce(state, draft => {
        draft[action.id].teams.push(action.team)
      })

    case Types.UPDATE_TEAM:
      return produce(state, draft => {
        const { teams } = draft[action.id]
        const idx = teams.findIndex(team => team.id === action.team.id)
        teams[idx] = action.team
      })

    case Types.REMOVE_TEAM:
      const changed = state[action.id].teams
        .filter(({ id }) => id !== action.teamId)

      return produce(state, draft => {
        draft[action.id].teams = changed
      })

    default:
      return state
  }
}
