import React, { Fragment, useState, useCallback } from 'react'
import PropTypes from 'prop-types'
import clsx from 'clsx'
import { debounce } from 'lodash-es'
import ScriptEditor from './ScriptEditor'
import { FaTrashAlt, FaHeart } from 'react-icons/fa'
import Button from 'components/shared/Button'
import classes from './Team.module.scss'

const Team = ({ team: originalTeam, running, stats, onChange, onRemove }) => {
  const [team, setTeam] = useState(originalTeam)
  const [editor, setEditor] = useState(false)

  const handleClose = () => setEditor(false)
  const syncState = () => setTeam(originalTeam)

  // eslint-disable-next-line react-hooks/exhaustive-deps
  const debounceOnChange = useCallback(
    debounce(t => onChange(t), 200),
    [onChange]
  )

  const update = team => {
    const count = parseInt(team.count) || 1

    setTeam(team)
    debounceOnChange({
      ...team,
      enabled: Boolean(team.enabled),
      count: count < 1 ? 1 : count
    })
  }

  const handleChange = field => event => {
    if (running) return;

    const value = field === 'enabled'
      ? event.target.checked
      : typeof event === 'object' ? event.target.value : event

    update({
      ...team,
      [field]: value
    })
  }

  const locked = running && team.enabled
  const statsView = locked && stats

  return (
    <div className={clsx(classes.container, team.enabled || classes.inactive)}>
      <div className={classes.header}>
        <div className={clsx(classes.wrapEnabled, locked && classes.invisible)}>
          <input
            type="checkbox"
            checked={team.enabled}
            onChange={handleChange('enabled')} />
        </div>
        <div className={classes.wrapColor}>
          <input
            type="color"
            disabled={locked}
            value={team.color}
            onChange={handleChange('color')} />
        </div>
        <div className={clsx(classes.wrapDelete, locked && classes.invisible)}>
          <Button variant="icon" onClick={onRemove}><FaTrashAlt /></Button>
        </div>
      </div>

      <div className={classes.wrapName}>
        <input
          type="text"
          placeholder="Team name"
          readOnly={locked}
          value={team.name}
          onChange={handleChange('name')} />
      </div>

      {
        statsView && <div style={{ padding: 20 }}>
          <FaHeart color="#e91e63" />
          <span style={{ fontFamily: 'monospace', fontSize: 16, paddingLeft: 10, fontWeight: 'bold' }}>
            {Math.round(100 * stats.currentHealth / stats.maxHealth)}%
          </span>
        </div>
      }

      {
        !statsView &&
          <Fragment>
            <div className={classes.wrapCount}>
              <input
                type="number"
                readOnly={locked}
                value={team.count}
                min="1"
                max="9999"
                onChange={handleChange('count')}
                onBlur={syncState} />
            </div>

            <div className={classes.wrapScript}>
              <Button variant="flat" onClick={() => setEditor(true)}>
                &lt;script&gt;
              </Button>
            </div>
          </Fragment>
      }

      {
        editor &&
          <ScriptEditor
            value={team.script}
            onChange={handleChange('script')}
            onClose={handleClose} />
      }
    </div>
  )
}

Team.displayName = 'Team'
Team.propTypes = {
  team: PropTypes.object.isRequired,
  stats: PropTypes.object,
  running: PropTypes.bool,
  onChange: PropTypes.func.isRequired,
  onRemove: PropTypes.func.isRequired
}

export default Team
