import Random from './random'
import Opposite from './opposite'
import { uniq } from 'lodash-es'

export default class Placement {
  constructor(mode, arena) {
    this.arena = arena;
    this.mode = mode;
  }

  applyTo(bots) {
    this.validate(bots);
    const klass = this.getKlass();
    new klass(this.arena).apply(bots);
  }

  validate(bots) {
    const teamNames = uniq(bots.map(bot => bot.name));

    if (this.mode === 'opposite' && teamNames.length !== 2) {
      console.warn('[Placement] "opposite" mode placement require having only 2 teams. Fallback to random placement')
      this.mode = 'random';
    }
  }

  getKlass() {
    switch (this.mode) {
      case 'random': return Random;
      case 'opposite': return Opposite;
      default:
        throw new Error(`[Placement] Unsupported placement mode: "${this.mode}"`);
    }
  }
}
