import React, { useRef, useEffect } from 'react'
import PropTypes from 'prop-types'
import { useSelector, useDispatch } from 'react-redux'
import Resize from './util/Resize'
import { updateSettings } from 'actions'

const Scene = ({ simulationId, setRenderContext, rendererResize }) => {
  const canvas = useRef(null)
  const dispatch = useDispatch()
  const { settings: { width, height }, running } = useSelector(store => {
    return store.simulations[simulationId]
  })

  const onResized = ({ width, height }) => {
    dispatch(updateSettings(simulationId, {
      width,
      height
    }))
  }

  useEffect(() => {
    setRenderContext(canvas.current)
  })

  return <div className="scene" style={{ padding: 15 }}>
    <Resize
      width={width}
      height={height}
      minWidth={200}
      minHeight={200}
      disabled={running}
      onResizing={rendererResize}
      onResized={onResized}
      style={{ border: '1px solid #000' }}
    >
      <div ref={canvas} />
    </Resize>
  </div>;
}

Scene.displayName = 'Scene'
Scene.propTypes = {
  simulationId: PropTypes.string.isRequired,
  setRenderContext: PropTypes.func.isRequired,
  rendererResize: PropTypes.func.isRequired
}

export default Scene
