import { hslToHex } from './color'
import { animals } from './names'

let hueIndex = 0

export function randomColor() {
  hueIndex += 40 + Math.round(Math.random() * 180)
  hueIndex %= 360

  return hslToHex(
    hueIndex,
    60 + Math.round(Math.random() * 40),
    80 + Math.round(Math.random() * 14)
  )
}

export function randomName() {
  const index = Math.floor(Math.random() * animals.length)
  return animals[index]
}

export function isWinPlatform() {
  try {
    return window.navigator.platform.startsWith('Win')
  } catch (e) {
    return false
  }
}
