import Team from './team'

export default class Teams {
  constructor(teams = []) {
    this.teams = [];
    teams.map(team => this.add(team));
  }

  get all() {
    return this.teams;
  }

  get active() {
    return this.all.filter(team => team.enabled);
  }

  add(data) {
    const team = new Team(data);
    this.teams.push(team);
    return team;
  }

  clear() {
    this.teams = [];
  }

  allBots() {
    return this.active.reduce((res, team) => {
      return res.concat(team.bots);
    }, []);
  }

  activeBots() {
    return this.allBots().filter(bot => bot.active);
  }

  stats() {
    return this.active.reduce((res, team) => {
      res[team.refId] = team.stats();
      return res;
    }, {});
  }

  toJson() {
    return this.activeBots().map(bot => bot.toJson());
  }
}
