import React, { useEffect, useRef } from 'react'
import SvgGauge from 'svg-gauge'
import classes from './Gauge.module.scss'

const DEFAULT_OPTIONS = {
  showValue: true,
  initialValue: 0,
  max: 100
}

const Gauge = props => {
  const gaugeEl = useRef(null)
  const gaugeRef = useRef(null)

  useEffect(() => {
    if (!gaugeRef.current) {
      const options = {
        ...DEFAULT_OPTIONS,
        ...props,
        gaugeClass: classes.gauge,
        dialClass: classes.dial,
        valueDialClass: classes.value,
        valueClass: classes.valueText
      }
      gaugeRef.current = SvgGauge(gaugeEl.current, options)
      gaugeRef.current.setValue(options.initialValue);
    }

    gaugeRef.current.setValueAnimated(props.value, 0.2);
  }, [props])

  return <div ref={gaugeEl} className={classes.container} />
}

Gauge.displayName = 'Gauge'

export default Gauge
