import Bot from './bot'

const DEFAULT_TEAM_CAPACITY = 3;
const DEFAULT_COLORS = [
  '#b0c4de',
  '#fafad2',
  '#7cfc00',
  '#c71585',
  '#5959ab'
];

let sequence = 0;

export default class Team {
  constructor(data) {
    sequence++;

    this.id = `team#${sequence}`;
    this.refId = data.id;
    this.name = data.name;
    this.color = data.color || this.randomColor();
    this.count = data.count || DEFAULT_TEAM_CAPACITY;
    this.enabled = data.enabled === undefined ? true : !!data.enabled;
    this.script = data.script;
    this.generateBots();
  }

  randomColor() {
    return DEFAULT_COLORS[sequence % DEFAULT_COLORS.length];
  }

  generateBots() {
    this.bots = [];

    for (let i = 0; i < this.count; i++) {
      this.bots.push(new Bot({
        id: [this.id, i].join('#'),
        team: this
      }));
    }

    return this.bots;
  }

  stats() {
    return {
      currentHealth: this.bots.reduce((res, bot) => res + bot.health, 0),
      maxHealth: this.bots.length * Bot.MAX_HEALTH,
      activeCount: this.bots.reduce((res, bot) => res + bot.active, 0),
      totalCount: this.bots.length
    }
  }
}
