import { some, random } from 'lodash-es'
import { distance } from '../math_helper'

const MIN_BOUND = 55;
const MAX_ITERATIONS = 100000;

export default class Random {
  constructor(arena) {
    this.arena = arena;
    this.minBound = arena.botRadius + MIN_BOUND;
  }

  apply(bots) {
    bots.forEach((bot, index) => {
      let coordinates;
      let iterations = 0;

      do {
        coordinates = this.randomCoordinates()
        if (iterations++ > MAX_ITERATIONS) {
          throw new Error('[Placement/Random] Cannot place bot. Too small arena size.')
        }

      } while (this.collide(coordinates, bots.slice(0, index)));

      bot.x = coordinates.x;
      bot.y = coordinates.y;
      bot.angle = random(359);
    });
  }

  randomCoordinates() {
    return {
      x: random(this.minBound, Math.max(this.arena.width - this.minBound, this.minBound)),
      y: random(this.minBound, Math.max(this.arena.height - this.minBound, this.minBound))
    }
  }

  collide(coordinates, bots) {
    return some(bots, bot => {
      const dis = distance(coordinates.x, coordinates.y, bot.x, bot.y);
      return dis < 2 * this.arena.botRadius;
    });
  }
}
