export const BOT_SAMPLE_SCRIPT = `\
let ticks = Math.round(1000 * Math.random());
const sign = ticks < 500 ? -1 : 1;

function action(my_state, enemies, shots, params) {
  let fire = false, range = 0;
  const target = enemies.find(e => e.team !== my_state.team);
  if (target) {
    const targetDirectionAngle = get_direction(my_state.x, my_state.y, target.x, target.y);
    const angleToTargetDirectionAngle = angle_size(my_state.angle, targetDirectionAngle);
    if (Math.abs(angleToTargetDirectionAngle) < 1 + 8 * Math.random()) {
      fire = true;
      range = Math.hypot(my_state.x - target.x, my_state.y - target.y);
    }
  }
  const speed = Math.round(ticks++ / 250) % 2 === 0 ? 0.5 : 0.2;
  return [speed, sign, fire, range];
}
`
