import Shot from './shot'

const MAX_EXPLODED_SHOTS = 80;

export default class Shots {
  constructor() {
    this.shots = new Set();
    this.explodedShots = [];
    this.explodedIndex = 0;
  }

  forEach(iteratee) {
    return this.shots.forEach(iteratee);
  }

  get length() {
    return this.shots.size;
  }

  add(data) {
    const shot = new Shot(data);
    this.shots.add(shot);
    return shot;
  }

  addToExploded(shot) {
    const index = this.explodedIndex++ % MAX_EXPLODED_SHOTS;
    this.explodedShots[index] = { x: shot.x, y: shot.y };
  }

  delete(shot) {
    this.shots.delete(shot);
    this.addToExploded(shot);
  }

  destroy() {
    this.shots.clear();
    this.explodedShots = [];
  }

  toJson() {
    return [...this.shots]
      .filter(shot => shot.exploded === false)
      .map(shot => shot.toJson());
  }
}
