import Arena from '../models/arena'
import Teams from '../models/teams'
import BaseRenderer  from './renderers/base'
import DomRenderer  from './renderers/dom'
import Engine from './engine'

const RUNNINGCHANGE_EVENT = 'runningchange'
const STATS_EVENT = 'statistics'

export default class Simulation {
  constructor() {
    this.arena = new Arena();
    this.teams = new Teams();
    this.renderer = new BaseRenderer();
    this.engine = null;
    this._running = false;
    this.events = {};
    console.log('New simulation created');
  }

  get running() {
    return this._running;
  }

  setRenderContext(context) {
    if (this.renderer && context === this.renderer.element) return;

    this.renderer = new DomRenderer(context);
    this.renderer.resize(this.arena.width, this.arena.height);

    if (this.running) {
      this.renderer.setup(this.engine.dataArguments);
      this.engine.renderer = this.renderer;
    }
  }

  setupTeams(teams = []) {
    this.teams.clear();
    teams.forEach(team => this.teams.add(team));
  }

  changeArena(params) {
    this.arena.update(params);
    this.renderer.resize(params.width, params.height);
  }

  start(options = {}) {
    if (this.running) return;

    this.engine = new Engine(this.teams, this.arena, this.renderer, options);
    this._running = true;
    this.trigger(RUNNINGCHANGE_EVENT, this.running);
    this.trigger(STATS_EVENT, this.getStats());

    const statsInterval = setInterval(() => {
      this.trigger(STATS_EVENT, this.getStats());
    }, 200);

    this.engine.run()
      .catch(console.error)
      .finally(() => {
        this.engine.destroy();
        this._running = false;
        this.trigger(RUNNINGCHANGE_EVENT, this.running);
        clearInterval(statsInterval);
      });
  }

  stop() {
    if (this.engine) {
      this.engine.stop();
    }
  }

  on(name, callback) {
    this.events[name] = this.events[name] || [];
    this.events[name].push(callback);

    return () => this.off(name, callback);
  }

  off(name, callback) {
    if (this.events[name]) {
      this.events[name] = this.events[name].filter(cb => cb !== callback);
    }
  }

  trigger(name, ...params) {
    const callbacks = this.events[name];
    callbacks && callbacks.forEach(cb => cb(...params));
  }

  getStats() {
    return {
      teams: this.teams.stats(),
      workers: this.engine.client.workersStats()
    }
  }
}
