import * as Types from './types'

export function addSimulation(id) {
  return {
    type: Types.ADD_SIMULATION,
    id,
    simulation: {
      teams: [],
      running: false,
      settings: {
        width: 700,
        height: 500,
        positionMode: 'random',
        bulletMode: 'vertical'
      }
    }
  }
}

export function updateSettings(id, changes) {
  return {
    type: Types.UPDATE_SETTINGS,
    id,
    changes
  }
}

export function setRunning(id, running) {
  return {
    type: Types.SET_RUNNING,
    id,
    running
  }
}

export function addTeam(id, team) {
  return {
    type: Types.ADD_TEAM,
    id,
    team
  }
}

export function updateTeam(id, team) {
  return {
    type: Types.UPDATE_TEAM,
    id,
    team
  }
}

export function removeTeam(id, teamId) {
  return {
    type: Types.REMOVE_TEAM,
    id,
    teamId
  }
}
