const MAX_HISTORY_TIMELINE = 5000
const DEFAULT_STATS_PERIOD = 1000

export default class Tracker {
  constructor() {
    this.jobsCount = 0;
    this.history = [];
  }

  load(period = DEFAULT_STATS_PERIOD) {
    const endPeriod = performance.now();
    const startPeriod = endPeriod - period;
    const history = [...this.history];
    let workPeriod = 0;

    for (let i = history.length - 1; i >= 0; i--) {
      const start = history[i][0];
      const end = history[i][1] || endPeriod;

      if (start >= startPeriod) {
        workPeriod += end - start;
      } else if (start < startPeriod && end > startPeriod) {
        workPeriod += end - startPeriod;
      } else {
        break;
      }
    }

    return workPeriod / period;
  }

  startJob() {
    const startTime = performance.now();

    if (this.jobsCount++ === 0) {
      this.history.push([startTime, null]);
      this.cleanOldHistoryData();
    }
  }

  stopJob() {
    if (--this.jobsCount === 0) {
      const lastItem = this.history[this.history.length - 1];
      lastItem[1] = performance.now();
    }
  }

  cleanOldHistoryData() {
    const freshStartTime = performance.now() - MAX_HISTORY_TIMELINE;
    const freshDataIndex = this.history.findIndex(([start, end]) => {
      return !end || end > freshStartTime;
    });
    this.history.splice(0, freshDataIndex);
  }
}
