import WorkerPool from './pool'

export default class Client {
  constructor(workerPool) {
    this.workerPool = workerPool || new WorkerPool();
    this.bots = {};
  }

  get workers() {
    return this.workerPool.workers;
  }

  workersStats() {
    return this.workerPool.stats();
  }

  registerBots(bots) {
    return Promise.all(bots.map(bot => this.registerBot(bot)));
  }

  registerBot(bot) {
    if (this.bots[bot.id]) {
      throw new Error(`[WorkerClient] Bot "${bot.id} already registered in worker pool"`);
    }

    const workerId = this.nextWorkerId();
    this.bots[bot.id] = { workerId };

    return this.workers[workerId]
      .postMessage(['register', bot.id, bot.script])
      .catch(response => {
        const error = (response && response.error) || response;
        return Promise.reject(error);
      });
  }

  async executeBots(bots, shots, params) {
    const promises = bots.map(bot => {
      const workerId = this.bots[bot.id].workerId;
      const enemies = bots.filter(b => b !== bot);
      const payload = [bot, enemies, shots, params];

      return this.workers[workerId].postMessage(['execute', bot.id, payload]);
    });

    const responses = await Promise.allSettled(promises) || [];

    return responses.reduce((result, response) => {
      if (response.status === 'fulfilled') {
        const [, id, payload] = response.value;
        result[id] = { payload: payload.result };
      } else {
        const { payload: [, id] } = response.reason;
        result[id] = { error: true };
      }

      return result;
    }, {});
  }

  nextWorkerId() {
    const ids = Object.keys(this.workerPool.workers);
    const botCount = Object.keys(this.bots).length;
    return ids[botCount % ids.length];
  }

  destroy() {
    this.workerPool.destroy();
  }
}
