import React, { Fragment } from 'react'
import PropTypes from 'prop-types'
import classes from './Resize.module.scss'

class Resize extends React.Component {
  constructor(props) {
    super(props)

    this.state = {
      mode: null,
      triggerState: null,
      size: {
        width: props.width,
        height: props.height
      }
    }

    this.onMouseDown = this.onMouseDown.bind(this)
    this.onMouseMove = this.onMouseMove.bind(this)
    this.onMouseUp = this.onMouseUp.bind(this)
  }

  setSize(size) {
    this.setState(prev => ({ ...prev, size }))

    const { onResizing } = this.props
    this.state.mode && onResizing && onResizing(size)
  }

  setMode(mode) {
    this.setState(prev => ({ ...prev, mode }))
  }

  setTriggerState(triggerState) {
    this.setState(prev => ({ ...prev, triggerState }))
  }

  normalizeX(x) {
    const { minWidth } = this.props
    return minWidth === undefined ? x : Math.max(x, minWidth)
  }

  normalizeY(y) {
    const { minHeight } = this.props
    return minHeight === undefined ? y : Math.max(y, minHeight)
  }

  onMouseDown(mode) {
    return event => {
      this.setTriggerState({
        x: event.pageX,
        y: event.pageY,
        width: this.state.size.width,
        height: this.state.size.height
      })
      this.setMode(mode)
    }
  }

  onMouseMove(event) {
    const { mode, size, triggerState } = this.state

    if (mode) {
      const moveX = event.pageX - triggerState.x
      const moveY = event.pageY - triggerState.y

      switch (mode) {
        case 'e':
          this.setSize({
            ...size,
            width: this.normalizeX(triggerState.width + moveX)
          })
          break;
        case 'n':
          this.setSize({
            ...size,
            height: this.normalizeY(triggerState.height + moveY)
          })
          break;
        case 'ne':
          this.setSize({
            width: this.normalizeX(triggerState.width + moveX),
            height: this.normalizeY(triggerState.height + moveY)
          })
          break;
        default:
          break;
      }
    }
  }

  onMouseUp() {
    const { mode, size } = this.state

    if (mode) {
      this.setMode(null)
      this.props.onResized && this.props.onResized(size)
    }
  }

  registerMouseEvents() {
    document.addEventListener('mousemove', this.onMouseMove)
    document.addEventListener('mouseup', this.onMouseUp)
  }

  unregisterMouseEvents() {
    document.removeEventListener('mousemove', this.onMouseMove)
    document.removeEventListener('mouseup', this.onMouseUp)
  }

  componentDidMount() {
    this.registerMouseEvents()
  }

  componentWillUnmount() {
    this.unregisterMouseEvents()
  }

  componentDidUpdate(prevProps, prevState) {
    const { disabled, width, height } = this.props

    if (prevProps.disabled !== disabled) {
      disabled ? this.unregisterMouseEvents() : this.registerMouseEvents()
    }

    if (prevProps.width !== width || prevProps.height !== height) {
      const { size } = this.state

      if (size.width !== width || size.height !== height) {
        this.setSize({ width, height })
      }
    }
  }

  render() {
    const { style, children, disabled } = this.props
    const { size } = this.state

    return (
      <div
        className={classes.container}
        style={{ ...style, width: size.width, height: size.height }}
      >
        {
          !disabled &&
            <Fragment>
              <div className={classes.eTrigger} onMouseDown={this.onMouseDown('e')}/>
              <div className={classes.nTrigger} onMouseDown={this.onMouseDown('n')}/>
              <div className={classes.neTrigger} onMouseDown={this.onMouseDown('ne')}/>
            </Fragment>
        }

        {children}
      </div>
    )
  }
}

Resize.displayName = 'Resize'
Resize.propTypes = {
  width: PropTypes.number.isRequired,
  height: PropTypes.number.isRequired,
  minWidth: PropTypes.number,
  minHeight: PropTypes.number,
  onResizing: PropTypes.func,
  onResized: PropTypes.func,
  disabled: PropTypes.bool,
  style: PropTypes.object,
}

export default Resize
