import {
  distanceBetweenObjects,
  directionBetweenObjects,
  angleSize,
  distance
} from '../math_helper'

const MAX_EXPLOSION_DAMAGE = 20;
const EXPLOSION_EFFECT_DISTANCE = 45;

export default class Shots {
  constructor({ arena, teams, shots }) {
    this.arena = arena;
    this.teams = teams;
    this.shots = shots;
  }

  execute(bulletMode) {
    const isHorizontal = bulletMode === "horizontal";
    const toBeRemoved = [];

    this.shots.forEach(shot => {
      let collisionDist = -1;
      if (isHorizontal && !shot.exploded) {
        collisionDist = this.horizontalCollisionDistance(shot);
      }

      if (collisionDist !== -1) {
        shot.move(collisionDist);
        shot.range = 0;
      }
      else if (shot.range <= this.arena.shotSpeed && shot.range > 0.0) {
        shot.move(shot.range);
        shot.range = 0;
      }
      else if (shot.range > this.arena.shotSpeed) {
        shot.move(this.arena.shotSpeed);
      }

      if (shot.range <= 0.0 || collisionDist !== -1) {
        shot.exploded = true;
        shot.explosionAnimationCounter++;

        if (shot.explosionStarted()) {
          this.applyExplosion(shot);
        }
        else if (shot.explosionFinished()) {
          toBeRemoved.push(shot);
        }
      }
    });

    toBeRemoved.forEach(shot => this.shots.delete(shot));
  }

  applyExplosion(shot) {
    this.teams.activeBots().forEach(bot => {
      const dist = distanceBetweenObjects(shot, bot);

      if (dist <= EXPLOSION_EFFECT_DISTANCE) {
        bot.health -= MAX_EXPLOSION_DAMAGE * (1 - dist / EXPLOSION_EFFECT_DISTANCE);
        bot.health <= 0.0 && bot.kill();
      }
    });
  }

  horizontalCollisionDistance(shot) {
    const bots = this.teams.activeBots().filter(bot => bot.id !== shot.shooter);
    const shotStepRange = this.arena.shotSpeed > shot.range ? shot.range : this.arena.shotSpeed;
    let result = -1;

    for (let bot of bots) {
      const dis = distanceBetweenObjects(shot, bot);
      if (dis > this.arena.botRadius + shotStepRange) continue;

      const dirToRobot = directionBetweenObjects(shot, bot);
      const angleShotToRobot = Math.abs(angleSize(shot.angle, dirToRobot));
      if (angleShotToRobot > 90) continue;

      const catetDis = dis * Math.cos(angleShotToRobot * Math.PI / 180);
      const catetShift = dis * Math.sin(angleShotToRobot * Math.PI / 180);
      if (catetShift > this.arena.botRadius) continue;
      // if (catetDis > (this.arena.botRadius + shotStepRange)) continue;

      if (catetDis <= shotStepRange) {
        let disShift = catetDis - Math.sqrt(Math.pow(this.arena.botRadius, 2) - Math.pow(catetShift, 2));
        if (disShift < 0) disShift = 0;
        if (result < 0 || result > disShift) result = disShift;

      } else {
        const nextShotX = shot.x + shotStepRange * Math.cos(shot.angle * Math.PI / 180);
        const nextShotY = shot.y - shotStepRange * Math.sin(shot.angle * Math.PI / 180);
        const dis2 = distance(nextShotX, nextShotY, bot.x, bot.y);

        if (dis2 <= this.arena.botRadius) {
          const disShift = catetDis - Math.sqrt(Math.pow(this.arena.botRadius, 2) - Math.pow(catetShift, 2));
          if (result < 0 || result > disShift) result = disShift;
        }
      }
    }

    return result;
  }
}
