import { isString, isNumber } from 'lodash-es'

const MAX_EXPLOSION_ANIMATION_COUNTER = 50;

export default class Shot {
  constructor(params = {}) {
    this.validateParams(params);

    this.shooter = params.shooter;
    this.x = params.x;
    this.y = params.y;
    this.range = params.range;
    this.angle = params.angle;
    this.exploded = false;
    this.explosionAnimationCounter = 0;
  }

  validateParams(params) {
    ['x', 'y', 'range', 'angle'].forEach(name => {
      if (!isNumber(params[name])) {
        throw new Error(`[Shot] '${name}' has invalid value`);
      }
    });

    if (!isString(params.shooter)) {
      throw new Error("[Shot] 'shooter' has invalid value");
    }
  }

  move(value) {
    this.x += value * Math.cos(this.angle * Math.PI / 180);
    this.y -= value * Math.sin(this.angle * Math.PI / 180);
    this.range -= value;
  }

  explosionStarted() {
    return this.explosionAnimationCounter === 1;
  }

  explosionFinished() {
    return this.explosionAnimationCounter > MAX_EXPLOSION_ANIMATION_COUNTER;
  }

  toJson() {
    return {
      x: this.x,
      y: this.y,
      range: this.range,
      angle: this.angle,
      shooter: this.shooter
    };
  }
}
