import { createContext, useContext } from 'react'
import SimulationEngine from 'core/simulation'

const ENGINE_CACHE = {}
const CONTEXT_CACHE = {}

export const lookupSimulationEngine = id => {
  ENGINE_CACHE[id] = ENGINE_CACHE[id] || new SimulationEngine()
  return ENGINE_CACHE[id]
}

export const lookupSimulationContext = id => {
  CONTEXT_CACHE[id] = CONTEXT_CACHE[id] || createContext({})
  return CONTEXT_CACHE[id]
}

export const useSimulationContext = id => {
  return useContext(lookupSimulationContext(id))
}
