import { isEmpty, groupBy, chunk } from 'lodash-es'

const MIN_BOUND_DELTA = 15;
const MAX_BOUND_DELTA = 30;
const NORMAL_TEAM_HEIGHT_RATIO = 1/3;
const PADDING = 40;

export default class Opposite {
  constructor(arena) {
    this.arena = arena;
    this.minBound = 2 * (arena.botRadius + MIN_BOUND_DELTA);
    this.maxBound = 2 * (arena.botRadius + MAX_BOUND_DELTA);
    this.width = Math.max(arena.width - 2 * PADDING, 0);
    this.height = Math.max(arena.height - 2 * PADDING, 0);

    this.allowedTeamColumns = Math.floor(this.width / this.minBound);
    this.allowedTeamRows = Math.floor(this.height / (2 * this.minBound));
    this.maxTeamCapacity = this.allowedTeamRows * this.allowedTeamColumns;
  }

  apply(bots) {
    if (isEmpty(bots)) return;

    const teams = Object.values(groupBy(bots, 'name'));
    this.validate(teams);
    teams.map((team, index) => this.placeTeam(team, index === 0));
  }

  placeTeam(bots, isTop) {
    const rows = Math.ceil(bots.length / this.allowedTeamColumns);
    const countPerRow = Math.ceil(bots.length / rows);
    const boundWidth = this.width / countPerRow;
    const draftBoundHeight = (this.height * NORMAL_TEAM_HEIGHT_RATIO) / rows;
    const boundHeight = Math.min(Math.max(draftBoundHeight, this.minBound), this.maxBound);

    chunk(bots, countPerRow).forEach((rowBots, rowIndex) => {
      rowBots.forEach((bot, index) => {
        bot.x = Math.ceil(PADDING + boundWidth * (index + 0.5));
        bot.y = Math.ceil(PADDING + boundHeight * (rowIndex + 0.5));
        if (!isTop) bot.y = this.arena.height - bot.y;
        bot.angle = isTop ? 90 : 270;
      });
    });
  }

  validate(teams) {
    if (teams.length !== 2) {
      throw new Error(`[Placement/Opposite] Requires exactly 2 teams, but got ${teams.length}`)
    }

    if (teams[0].length > this.maxTeamCapacity || teams[1].length > this.maxTeamCapacity) {
      throw new Error('[Placement/Opposite] One or more teams are to big for arena size')
    }
  }
}
