import React from 'react'
import PropTypes from 'prop-types'
import { useSelector, useDispatch } from 'react-redux'
import Button from 'components/shared/Button'
import Team from './Team'
import { addTeam, updateTeam, removeTeam } from 'actions'
import { FaPlus } from 'react-icons/fa'
import { BOT_SAMPLE_SCRIPT } from 'helpers/botScripts'
import { randomColor, randomName } from 'helpers/utils'
import { useSimulationContext } from 'helpers/simulationCache'

const Teams = ({ simulationId: id }) => {
  const dispatch = useDispatch()
  const { teams, running } = useSelector(store => store.simulations[id])
  const { teams: teamsStats = {} } = useSimulationContext(id)

  const handleNewTeam = () => {
    if (running) return;

    const ids = teams.map(({ id }) => id)

    dispatch(addTeam(id, {
      id: Math.max(0, ...ids) + 1,
      name: randomName(),
      color: randomColor(),
      enabled: true,
      count: 1,
      script: BOT_SAMPLE_SCRIPT
    }))
  }

  const handleUpdateTeam = team => {
    dispatch(updateTeam(id, team))
  }

  const handleRemoveTeam = teamId => () => {
    dispatch(removeTeam(id, teamId))
  }

  return (
    <div style={{ display: 'flex', flexDirection: 'row' }}>
      {
        teams.map(team => (
          <Team
              key={team.id}
              team={team}
              stats={teamsStats[team.id]}
              running={running}
              onChange={handleUpdateTeam}
              onRemove={handleRemoveTeam(team.id)}
            />
        ))
      }
      <div style={{ display: 'flex', alignItems: 'center' }}>
        <Button
          variant={running ? 'button-disabled' : 'button'}
          onClick={handleNewTeam}
          style={{ padding: 6 }}>
          <FaPlus size="1.5em" />
        </Button>
      </div>
    </div>
  )
}

Teams.displayName = 'Teams'
Teams.propTypes = {
  simulationId: PropTypes.string.isRequired
}

export default Teams
