import React, { useState, useEffect } from 'react'
import PropTypes from 'prop-types'
import Modal from 'components/util/Modal'
import { isWinPlatform } from 'helpers/utils'
import { Controlled as CodeMirror } from 'react-codemirror2'
import 'codemirror/mode/javascript/javascript'
import 'codemirror/lib/codemirror.css'
import classes from './ScriptEditor.module.scss'

const ScriptEditor = ({ value, onChange, onClose }) => {
  const [code, setCode] = useState(value);
  let editor

  useEffect(() => {
    if (editor) {
      setTimeout(editor.refresh.bind(editor))
    }
  })

  const handleClose = () => {
    onChange(code)
    onClose()
  }

  return (
    <Modal
      open
      backdrop={false}
      onClose={handleClose}
      style={{ top: '10%', left: '10%', width: '80%', height: '70%' }}
    >
      <div className="draggable">
        <button onClick={handleClose} style={{ float: 'right' }}>x</button>
      </div>

      <CodeMirror
        className={classes.editor}
        value={code}
        editorDidMount={e => editor = e}
        onBeforeChange={(editor, data, value) => setCode(value) }
        options={{
          mode: 'javascript',
          lineNumbers: true,
          keyMap: isWinPlatform ? 'pcDefault' : 'default'
        }}
      />
    </Modal>
  )
}

ScriptEditor.displayName = 'ScriptEditor'
ScriptEditor.propTypes = {
  value: PropTypes.string,
  onChange: PropTypes.func.isRequired,
  onClose: PropTypes.func
}

export default ScriptEditor
