const AVG_HISTORY_NUMBER = 20;

export default class FpsMeter {
  constructor(historyAverage) {
    this.historyAverage = historyAverage || AVG_HISTORY_NUMBER;
    this.history = [];
    this.currentIndex = 0;
  }

  average() {
    if (!this.history.length) return 0;
    const sum = this.history.reduce((s, i) => s + i);
    return sum / this.history.length;
  }

  averageInt() {
    return Math.round(this.average());
  }

  track(value) {
    this.history[this.currentIndex % this.historyAverage] = value;
    this.currentIndex++;
  }

  reset() {
    this.history = [];
    this.currentIndex = 0;
  }
}
